public static void RemoveExpired(List<Session> sessions, DateTime cutoff)
{
    foreach (var session in sessions)
    {
        if (session.LastSeen < cutoff)
        {
            sessions.Remove(session);
        }
    }
}

public record Session(string Id, DateTime LastSeen);

