public static List<string> ActiveCustomerEmails(IEnumerable<Customer> customers)
{
    var result = new List<string>();
    foreach (var c in customers)
    {
        if (c.IsActive)
        {
            if (!result.Contains(c.Email))
            {
                result.Add(c.Email);
            }
        }
    }
    result.Sort();
    return result;
}

public record Customer(string Name, string Email, bool IsActive);

public static decimal CalculateDiscount(Order order)
{
    if (order != null)
    {
        if (order.Items.Count > 0)
        {
            if (order.Customer.IsActive)
            {
                if (order.Total > 100)
                {
                    return order.Total * 0.10m;
                }
                else
                {
                    return 0m;
                }
            }
            else
            {
                return 0m;
            }
        }
        else
        {
            return 0m;
        }
    }
    else
    {
        throw new ArgumentNullException(nameof(order));
    }
}

public User? FindUserByEmail(string email)
{
    using var connection = new SqlConnection(_connectionString);
    connection.Open();

    var sql = "SELECT Id, Name FROM Users WHERE Email = '" + email + "'";
    using var command = new SqlCommand(sql, connection);

    using var reader = command.ExecuteReader();
    if (!reader.Read()) return null;
    return new User(reader.GetGuid(0), reader.GetString(1));
}

public static string FormatUsd(decimal amount)
{
    if (amount < 0) return "-" + FormatUsd(-amount);
    return amount.ToString("C2", new CultureInfo("en-US"));
}

